import { loadSession, saveSession, clearSession } from './packages/sdlc-agent/dist/session.js';
import { mkdtempSync, existsSync, readFileSync } from 'node:fs';
import { tmpdir } from 'node:os';
import { join } from 'node:path';

const tmp = mkdtempSync(join(tmpdir(), 'sdlc-uat-'));

// AC6: session persists across iterations at .sdlc/features/<slug>/.agent-session
console.log('1. No session initially:', loadSession(tmp, 'test-feature'));
saveSession(tmp, 'test-feature', 'session-abc-123');
const loaded = loadSession(tmp, 'test-feature');
console.log('2. Session saved and loaded:', loaded);
const path = join(tmp, '.sdlc/features/test-feature/.agent-session');
console.log('3. File exists:', existsSync(path));
console.log('4. Raw content:', readFileSync(path, 'utf8').trim());
clearSession(tmp, 'test-feature');
console.log('5. After clear:', loadSession(tmp, 'test-feature'));
" 2>&1

