import { runGates, allGatesPassed, formatGateResults } from './packages/sdlc-agent/dist/gates.js';

// AC4: shell gates run before approve
const gates = [
  { name: 'echo-gate', type: 'shell', command: 'echo hello', auto: true },
  { name: 'human-gate', type: 'human', auto: false },
  { name: 'fail-gate', type: 'shell', command: 'false', auto: true },
];

const results = await runGates(gates, '/tmp');
console.log('Shell gate passed:', results[0].passed);
console.log('Human gate skipped (passed=true):', results[1].passed, results[1].output);
console.log('Fail gate failed:', !results[2].passed);
console.log('allGatesPassed:', allGatesPassed(results));
console.log('Format output:');
console.log(formatGateResults(results));
" 2>&1

